import{c as e,Q as d,j as a,m as r}from"./chunks/framework.DVkeSyfh.js";const b=JSON.parse('{"title":"API reference","description":"","frontmatter":{},"headers":[],"relativePath":"ru/reference/api.md","filePath":"ru/reference/api.md","lastUpdated":null}'),o={name:"ru/reference/api.md"};function s(c,t,i,l,n,p){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="api-reference" tabindex="-1">API reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API reference&quot;">​</a></h1><p>Аудитория: developers и frontend integrators<br> Цель: показать current endpoint groups и main payload models<br> Тип: reference</p><p>FastAPI app создается через <code>dj_track_similarity.api:create_app</code>. Она mounts built docs at <code>/docs</code>, если существует <code>docs/dj-track-similarity/site</code>, и frontend bundle at <code>/</code>, если существует <code>frontend/dist</code>.</p><h2 id="database-and-library" tabindex="-1">Database and library <a class="header-anchor" href="#database-and-library" aria-label="Permalink to &quot;Database and library&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET /api/database/current</code></td><td>current selected database</td></tr><tr><td><code>POST /api/database/switch</code></td><td>switch database path</td></tr><tr><td><code>POST /api/database/dialog</code></td><td>open native database dialog</td></tr><tr><td><code>POST /api/library/scan</code></td><td>start scan job</td></tr><tr><td><code>POST /api/library/tags/refresh</code></td><td>refresh stored tag metadata</td></tr><tr><td><code>POST /api/library/relocate</code></td><td>preview/apply stored path relocation</td></tr><tr><td><code>POST /api/database/clear</code></td><td>clear selected database state</td></tr><tr><td><code>GET /api/tracks</code></td><td>paginated/searchable lightweight track rows</td></tr><tr><td><code>GET /api/tracks/{track_id}</code></td><td>full track details</td></tr><tr><td><code>POST /api/tracks/{track_id}/liked</code></td><td>toggle liked state</td></tr><tr><td><code>GET /api/library/summary</code></td><td>library counters</td></tr><tr><td><code>GET /media/{track_id}</code></td><td>local media preview</td></tr></tbody></table><h2 id="analysis-and-classifiers" tabindex="-1">Analysis and classifiers <a class="header-anchor" href="#analysis-and-classifiers" aria-label="Permalink to &quot;Analysis and classifiers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST /api/analysis/jobs</code></td><td>start analysis job</td></tr><tr><td><code>GET /api/analysis/jobs/latest</code></td><td>latest analysis job</td></tr><tr><td><code>GET /api/analysis/jobs/{job_id}</code></td><td>job status</td></tr><tr><td><code>POST /api/analysis/jobs/{job_id}/cancel</code></td><td>cancel job</td></tr><tr><td><code>POST /api/analysis/reset</code></td><td>reset selected analysis state</td></tr><tr><td><code>GET /api/classifiers</code></td><td>promoted classifiers</td></tr><tr><td><code>POST /api/classifiers/{classifier_key}/analyze</code></td><td>score one classifier</td></tr><tr><td><code>POST /api/classifiers/reset</code></td><td>reset classifier scores</td></tr><tr><td><code>GET /api/classifiers/{classifier_key}/calibration-report</code></td><td>report</td></tr><tr><td><code>GET /api/classifiers/{classifier_key}/label-suggestions</code></td><td>suggestions</td></tr></tbody></table><h2 id="search-and-set" tabindex="-1">Search and SET <a class="header-anchor" href="#search-and-set" aria-label="Permalink to &quot;Search and SET&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST /api/search</code></td><td>MERT seed search</td></tr><tr><td><code>POST /api/search/sonara</code></td><td>SONARA feature search</td></tr><tr><td><code>POST /api/search/text</code></td><td>CLAP text search</td></tr><tr><td><code>POST /api/search/hybrid</code></td><td>weighted hybrid search</td></tr><tr><td><code>POST /api/set-builder/generate</code></td><td>Smart Set Builder preview</td></tr></tbody></table><h2 id="export-tags-tools" tabindex="-1">Export, tags, tools <a class="header-anchor" href="#export-tags-tools" aria-label="Permalink to &quot;Export, tags, tools&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST /api/export</code></td><td>export selected/current set</td></tr><tr><td><code>POST /api/tags/genres/apply</code></td><td>explicit standard genre write</td></tr><tr><td><code>POST /api/tags/genres/jobs</code></td><td>genre tag write job</td></tr><tr><td><code>POST /api/audio-dedup/jobs</code></td><td>duplicate report/apply job</td></tr><tr><td><code>GET /api/audio-dedup/jobs/{job_id}/report/xlsx</code></td><td>XLSX report</td></tr><tr><td><code>GET /api/rhythm-lab/status</code></td><td>lab process status</td></tr><tr><td><code>POST /api/rhythm-lab/launch</code></td><td>launch lab</td></tr><tr><td><code>POST /api/rhythm-lab/stop</code></td><td>stop lab</td></tr><tr><td><code>POST /api/dialog/folder</code></td><td>native folder dialog</td></tr></tbody></table><h2 id="important-request-models" tabindex="-1">Important request models <a class="header-anchor" href="#important-request-models" aria-label="Permalink to &quot;Important request models&quot;">​</a></h2><p><code>AnalysisJobRequest</code> includes <code>limit</code>, <code>models</code>, <code>classifier_keys</code>, <code>device</code>, <code>top_k</code>, <code>track_batch_size</code> and <code>inference_batch_size</code>.</p><p><code>SetBuilderGenerateRequest</code> includes seed mode, auto anchor count, set mode, limit, diversity, energy curve, BPM mode/change/start/target and classifier preferences/flows.</p><p><code>AudioDedupJobRequest</code> includes root/path filters, preset, thresholds, group limit, output directory, apply flag and confirmation text.</p>',15)])])}const u=e(o,[["render",s]]);export{b as __pageData,u as default};
